  3→import androidx.lifecycle.ViewModel
  4→import androidx.lifecycle.viewModelScope
  5→import dagger.hilt.android.lifecycle.HiltViewModel
  6→import kotlinx.coroutines.flow.MutableStateFlow
  7→import kotlinx.coroutines.flow.StateFlow
  8→import kotlinx.coroutines.flow.asStateFlow
  9→import kotlinx.coroutines.flow.update
 10→import kotlinx.coroutines.launch
 11→import pub.hackers.android.data.repository.HackersPubRepository
 12→import pub.hackers.android.domain.model.Notification
 13→import java.time.Instant
 14→import javax.inject.Inject
 15→
 16→data class NotificationsUiState(
 17→    val notifications: List<Notification> = emptyList(),
 18→    val isLoading: Boolean = false,
 19→    val isRefreshing: Boolean = false,
 20→    val isLoadingMore: Boolean = false,
 21→    val hasNextPage: Boolean = false,
 22→    val endCursor: String? = null,
 23→    val error: String? = null
 24→)
 25→
 26→@HiltViewModel
 27→class NotificationsViewModel @Inject constructor(
 28→    private val repository: HackersPubRepository
 29→) : ViewModel() {
 30→
 31→    private val _uiState = MutableStateFlow(NotificationsUiState())
 32→    val uiState: StateFlow<NotificationsUiState> = _uiState.asStateFlow()
 33→
 34→    private var lastLoadTime: Instant? = null
 35→    private val staleThresholdSeconds = 60L
 36→
 37→    init {
 38→        loadNotifications()
 39→    }
 40→
 41→    fun refreshIfStale() {
 42→        val last = lastLoadTime ?: return
 43→        if (Instant.now().epochSecond - last.epochSecond > staleThresholdSeconds) {
 44→            refresh()
 45→        }
 46→    }
 47→
 48→    private fun loadNotifications() {
 49→        viewModelScope.launch {
 50→            _uiState.update { it.copy(isLoading = true, error = null) }
 51→
 52→            repository.getNotifications()
 53→                .onSuccess { result ->
 54→                    lastLoadTime = Instant.now()
 55→                    _uiState.update {
 56→                        it.copy(
 57→                            notifications = result.notifications,
 58→                            hasNextPage = result.hasNextPage,
 59→                            endCursor = result.endCursor,
 60→                            isLoading = false
 61→                        )
 62→                    }
 63→                }
 64→                .onFailure { error ->
 65→                    _uiState.update {
 66→                        it.copy(
 67→                            error = error.message,
 68→                            isLoading = false
 69→                        )
 70→                    }
 71→                }
 72→        }
 73→    }
 74→
 75→    fun refresh() {
 76→        viewModelScope.launch {
 77→            _uiState.update { it.copy(isRefreshing = true, error = null) }
 78→
 79→            repository.getNotifications(refresh = true)
 80→                .onSuccess { result ->
 81→                    lastLoadTime = Instant.now()
 82→                    _uiState.update {
 83→                        it.copy(
 84→                            notifications = result.notifications,
 85→                            hasNextPage = result.hasNextPage,
 86→                            endCursor = result.endCursor,
 87→                            isRefreshing = false
 88→                        )
 89→                    }
 90→                }
 91→                .onFailure { error ->
 92→                    _uiState.update {
 93→                        it.copy(
 94→                            error = error.message,
 95→                            isRefreshing = false
 96→                        )
 97→                    }
 98→                }
 99→        }
100→    }
101→
102→    fun loadMore() {
103→        val currentState = _uiState.value
104→        if (!currentState.hasNextPage || currentState.isLoadingMore) return
105→
106→        viewModelScope.launch {
107→            _uiState.update { it.copy(isLoadingMore = true) }
108→
109→            repository.getNotifications(after = currentState.endCursor)
110→                .onSuccess { result ->
111→                    _uiState.update {
112→                        it.copy(
113→                            notifications = it.notifications + result.notifications,
114→                            hasNextPage = result.hasNextPage,
115→                            endCursor = result.endCursor,
116→                            isLoadingMore = false
117→                        )
118→                    }
119→                }
120→                .onFailure {
121→                    _uiState.update { it.copy(isLoadingMore = false) }
122→                }
123→        }
124→    }
125→}
