  2→
  3→import android.content.Context
  4→import androidx.lifecycle.ViewModel
  5→import androidx.lifecycle.viewModelScope
  6→import com.apollographql.apollo.ApolloClient
  7→import com.apollographql.apollo.cache.normalized.apolloStore
  8→import dagger.hilt.android.lifecycle.HiltViewModel
  9→import dagger.hilt.android.qualifiers.ApplicationContext
 10→import kotlinx.coroutines.flow.MutableStateFlow
 11→import kotlinx.coroutines.flow.StateFlow
 12→import kotlinx.coroutines.flow.asStateFlow
 13→import kotlinx.coroutines.flow.first
 14→import kotlinx.coroutines.flow.update
 15→import kotlinx.coroutines.launch
 16→import pub.hackers.android.data.local.PreferencesManager
 17→import pub.hackers.android.data.local.SessionManager
 18→import pub.hackers.android.data.repository.HackersPubRepository
 19→import javax.inject.Inject
 20→
 21→data class SettingsUiState(
 22→    val userName: String? = null,
 23→    val userHandle: String? = null,
 24→    val userAvatar: String? = null,
 25→    val appVersion: String = "",
 26→    val cacheSize: String = "",
 27→    val isSignedOut: Boolean = false,
 28→    val message: String? = null,
 29→    val confirmBeforeDelete: Boolean = true,
 30→    val confirmBeforeShare: Boolean = false,
 31→    val timelineMaxLength: Int = 0,
 32→    val useInAppBrowser: Boolean = true,
 33→    val fontSizePercent: Int = 100
 34→)
 35→
 36→@HiltViewModel
 37→class SettingsViewModel @Inject constructor(
 38→    private val sessionManager: SessionManager,
 39→    private val preferencesManager: PreferencesManager,
 40→    private val repository: HackersPubRepository,
 41→    private val apolloClient: ApolloClient,
 42→    @ApplicationContext private val context: Context
 43→) : ViewModel() {
 44→
 45→    private val _uiState = MutableStateFlow(SettingsUiState())
 46→    val uiState: StateFlow<SettingsUiState> = _uiState.asStateFlow()
 47→
 48→    init {
 49→        loadUserInfo()
 50→        loadAppVersion()
 51→        loadPreferences()
 52→        calculateCacheSize()
 53→    }
 54→
 55→    private fun loadUserInfo() {
 56→        viewModelScope.launch {
 57→            val name = sessionManager.userName.first()
 58→            val handle = sessionManager.userHandle.first()
 59→            val avatar = sessionManager.userAvatar.first()
 60→
 61→            _uiState.update {
 62→                it.copy(
 63→                    userName = name,
 64→                    userHandle = handle,
 65→                    userAvatar = avatar
 66→                )
 67→            }
 68→        }
 69→    }
 70→
 71→    private fun loadAppVersion() {
 72→        try {
 73→            val packageInfo = context.packageManager.getPackageInfo(context.packageName, 0)
 74→            val version = packageInfo.versionName ?: "Unknown"
 75→            val versionCode = packageInfo.longVersionCode
 76→            _uiState.update { it.copy(appVersion = "$version ($versionCode)") }
 77→        } catch (_: Exception) {
 78→            _uiState.update { it.copy(appVersion = "Unknown") }
 79→        }
 80→    }
 81→
 82→    private fun loadPreferences() {
 83→        viewModelScope.launch {
 84→            val confirmDelete = preferencesManager.confirmBeforeDelete.first()
 85→            val confirmShare = preferencesManager.confirmBeforeShare.first()
 86→            val maxLength = preferencesManager.timelineMaxLength.first()
 87→            val inAppBrowser = preferencesManager.useInAppBrowser.first()
 88→            val fontSize = preferencesManager.fontSizePercent.first()
 89→
 90→            _uiState.update {
 91→                it.copy(
 92→                    confirmBeforeDelete = confirmDelete,
 93→                    confirmBeforeShare = confirmShare,
 94→                    timelineMaxLength = maxLength,
 95→                    useInAppBrowser = inAppBrowser,
 96→                    fontSizePercent = fontSize
 97→                )
 98→            }
 99→        }
100→    }
101→
102→    fun setConfirmBeforeDelete(value: Boolean) {
103→        _uiState.update { it.copy(confirmBeforeDelete = value) }
104→        viewModelScope.launch { preferencesManager.setConfirmBeforeDelete(value) }
105→    }
106→
107→    fun setConfirmBeforeShare(value: Boolean) {
108→        _uiState.update { it.copy(confirmBeforeShare = value) }
109→        viewModelScope.launch { preferencesManager.setConfirmBeforeShare(value) }
110→    }
111→
112→    fun setTimelineMaxLength(value: Int) {
113→        _uiState.update { it.copy(timelineMaxLength = value) }
114→        viewModelScope.launch { preferencesManager.setTimelineMaxLength(value) }
115→    }
116→
117→    fun setUseInAppBrowser(value: Boolean) {
118→        _uiState.update { it.copy(useInAppBrowser = value) }
119→        viewModelScope.launch { preferencesManager.setUseInAppBrowser(value) }
120→    }
121→
122→    fun setFontSizePercent(value: Int) {
123→        _uiState.update { it.copy(fontSizePercent = value) }
124→        viewModelScope.launch { preferencesManager.setFontSizePercent(value) }
125→    }
126→
127→    fun signOut() {
128→        viewModelScope.launch {
129→            val sessionId = sessionManager.sessionToken.first()
130→            if (sessionId != null) {
131→                repository.revokeSession(sessionId)
132→            }
133→            sessionManager.clearSession()
134→            apolloClient.apolloStore.clearAll()
135→            _uiState.update { it.copy(isSignedOut = true) }
136→        }
137→    }
138→
139→    private fun calculateCacheSize() {
140→        viewModelScope.launch {
141→            val cacheDir = context.cacheDir
142→            val size = getDirSize(cacheDir)
143→            _uiState.update { it.copy(cacheSize = formatBytes(size)) }
144→        }
145→    }
146→
147→    private fun getDirSize(dir: java.io.File): Long {
148→        var size = 0L
149→        if (dir.isDirectory) {
150→            dir.listFiles()?.forEach { file ->
151→                size += if (file.isDirectory) getDirSize(file) else file.length()
152→            }
153→        }
154→        return size
155→    }
156→
157→    private fun formatBytes(bytes: Long): String {
158→        return when {
159→            bytes < 1024 -> "$bytes B"
160→            bytes < 1024 * 1024 -> String.format("%.1f KB", bytes / 1024.0)
161→            bytes < 1024 * 1024 * 1024 -> String.format("%.1f MB", bytes / (1024.0 * 1024))
162→            else -> String.format("%.1f GB", bytes / (1024.0 * 1024 * 1024))
163→        }
164→    }
165→
166→    fun clearCache() {
167→        viewModelScope.launch {
168→            try {
169→                apolloClient.apolloStore.clearAll()
170→                // Also clear file cache
171→                context.cacheDir.listFiles()?.forEach { it.deleteRecursively() }
172→                calculateCacheSize()
173→                _uiState.update { it.copy(message = "Cache cleared") }
174→            } catch (e: Exception) {
175→                _uiState.update { it.copy(message = "Failed to clear cache") }
176→            }
177→        }
178→    }
179→
180→    fun clearMessage() {
181→        _uiState.update { it.copy(message = null) }
182→    }
183→}
